import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toppingsList from '../toppings';
import he from '../i18n/he.json';

const BASE_PRICE = 30;
const TOPPING_PRICE = 8;

export default function PizzaMenu() {
  const [selectedToppings, setSelectedToppings] = useState([]);
  const navigate = useNavigate();
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  const handleToppingChange = topping => {
    setSelectedToppings(prev =>
      prev.includes(topping)
        ? prev.filter(t => t !== topping)
        : [...prev, topping]
    );
  };

  const handleAddToCart = () => {
    const cart = {
      toppings: selectedToppings,
      total: BASE_PRICE + selectedToppings.length * TOPPING_PRICE,
    };
    localStorage.setItem('cart', JSON.stringify(cart));
    navigate('/cart');
  };

  return (
    <div className="max-w-md mx-auto mt-6">
      {/* Red Top Nav */}
      <div className="flex items-center justify-between px-5 py-3 bg-tomato text-white rounded-t-2xl shadow-md">
        <h1 className="text-xl font-bold">🍕 {he.app_title}</h1>
        <div className="flex gap-2">
          {auth.verified ? (
            <>
              <button
                onClick={() => navigate('/history')}
                className="bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-lg text-xs font-semibold transition"
              >
                הזמנות
              </button>
              <button
                onClick={() => navigate('/tracker')}
                className="bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-lg text-xs font-semibold transition"
              >
                מעקב
              </button>
            </>
          ) : (
            <button
              onClick={() => navigate('/login')}
              className="bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-lg text-xs font-semibold transition"
            >
              כניסה
            </button>
          )}
        </div>
      </div>

      {/* White Content Card */}
      <div className="p-6 bg-white rounded-b-2xl shadow-lg">
        <img
          src="https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=400&q=80"
          alt="pizza"
          className="w-full rounded-xl mb-4 shadow"
        />
        <h2 className="text-xl font-semibold mb-3">{he.menu_title}</h2>

        <div className="mb-5">
          <div className="flex justify-between mb-2 text-gray-700">
            <span>{he.base_pizza}</span>
            <span className="font-bold">{BASE_PRICE} ₪</span>
          </div>
          <div className="mb-2 font-semibold text-gray-700">
            {he.toppings}{' '}
            <span className="text-tomato font-normal text-sm">({TOPPING_PRICE}₪ לתוספת)</span>
          </div>
          <div className="flex flex-wrap gap-2">
            {toppingsList.map(topping => (
              <label
                key={topping}
                className={`flex items-center gap-1 px-3 py-1.5 rounded-xl cursor-pointer border transition select-none
                  ${selectedToppings.includes(topping)
                    ? 'bg-tomato text-white border-tomato shadow-sm'
                    : 'bg-crust border-transparent hover:border-tomato'}`}
              >
                <input
                  type="checkbox"
                  checked={selectedToppings.includes(topping)}
                  onChange={() => handleToppingChange(topping)}
                  className="hidden"
                />
                {topping}
              </label>
            ))}
          </div>
        </div>

        <button
          onClick={handleAddToCart}
          className="w-full bg-tomato text-white py-3 rounded-xl font-bold text-lg hover:bg-red-700 transition shadow-md"
        >
          {he.cart} — {BASE_PRICE + selectedToppings.length * TOPPING_PRICE} ₪
        </button>
      </div>
    </div>
  );
}
